// IsValidMIMEType reports whether s is a valid IANA media (MIME) type.
func IsValidMIMEType(s string) bool { _, ok := validMIMETypes[s]; return ok }

// IsValidCharset reports whether s is a valid IANA character set name.
func IsValidCharset(s string) bool { _, ok := validCharsets[s]; return ok }

// IsValidProtocol reports whether s is a valid protocol (IANA service/transport + ipv4/ipv6/ssl/tls/dns).
func IsValidProtocol(s string) bool { _, ok := validProtocols[s]; return ok }

// IsValidIPFIXName reports whether s is a valid IANA IPFIX Information Element name.
func IsValidIPFIXName(s string) bool { _, ok := validIPFIXNames[s]; return ok }
